// Pull comments from YouTube for all published videos.
// Rewritten 2026-04-26 — pre-existing bug used this.helpers.httpRequest +
// process.env, both broken under n8n 2.8.4 task runner (6 consecutive cron
// failures since 2026-04-20, zero successes). Now uses fetch() + $env.

const SB = $env.SUPABASE_URL;
const ANON = $env.SUPABASE_ANON_KEY;
const SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
const YT = $env.YOUTUBE_API_KEY;

const sbHeaders = (extra = {}) => ({
  apikey: ANON,
  Authorization: `Bearer ${SRK}`,
  'Content-Type': 'application/json',
  ...extra
});

async function getJson(url, headers) {
  const r = await fetch(url, { method: 'GET', headers });
  if (!r.ok) throw new Error(`HTTP ${r.status}: ${(await r.text()).slice(0, 200)}`);
  return r.json();
}

const topics = await getJson(
  `${SB}/rest/v1/topics?status=eq.published&youtube_video_id=not.is.null&select=id,project_id,youtube_video_id,seo_title`,
  sbHeaders()
);

let synced = 0;
let topicsChecked = 0;

for (const topic of (Array.isArray(topics) ? topics : [])) {
  topicsChecked++;
  if (!topic.youtube_video_id || !YT) continue;

  try {
    const resp = await getJson(
      `https://www.googleapis.com/youtube/v3/commentThreads?part=snippet&videoId=${topic.youtube_video_id}&order=time&maxResults=20&key=${YT}`,
      { 'Content-Type': 'application/json' }
    );

    for (const item of (resp && Array.isArray(resp.items) ? resp.items : [])) {
      const c = item.snippet && item.snippet.topLevelComment && item.snippet.topLevelComment.snippet;
      const commentId = item.snippet && item.snippet.topLevelComment && item.snippet.topLevelComment.id;
      if (!c || !commentId) continue;

      // Idempotency: skip if comment already stored
      const existing = await getJson(
        `${SB}/rest/v1/comments?platform_comment_id=eq.${commentId}&select=id`,
        sbHeaders()
      );
      if (Array.isArray(existing) && existing.length > 0) continue;

      const insertRes = await fetch(`${SB}/rest/v1/comments`, {
        method: 'POST',
        headers: sbHeaders({ Prefer: 'return=minimal' }),
        body: JSON.stringify({
          topic_id: topic.id,
          project_id: topic.project_id,
          platform: 'youtube',
          platform_comment_id: commentId,
          author: c.authorDisplayName,
          author_avatar_url: c.authorProfileImageUrl,
          text: c.textOriginal || c.textDisplay,
          like_count: c.likeCount || 0
        })
      });
      if (insertRes.ok) synced++;
    }
  } catch (e) {
    // Continue with next topic. Per-topic failure is non-fatal so one
    // dead video does not break the whole nightly sync.
  }
}

return [{ json: { synced, topics_checked: topicsChecked } }];
